import{_ as e,c as d,a,o as r}from"./app-CEcM0piI.js";const i={};function s(n,t){return r(),d("div",null,t[0]||(t[0]=[a('<p>镜像就是包含了应用程序、程序运行的系统函数库、运行配置等文件的文件包。构建镜像的过程其实就是把上述文件打包的过程。</p><p>![[Pasted image 20250110132504.png]] 对于部分应用,它们可能有些层是相同的,这样在下载镜像的时候就可以跳过该层,这样可以加快下载速度,减少文件体积</p><h1 id="dockerfile" tabindex="-1"><a class="header-anchor" href="#dockerfile"><span>dockerfile</span></a></h1><p>Dockerfile就是一个文本文件，其中包含的指令nstruction）令来说明要执行什么操作来构建镜像。将来Docker可以根据Dockerfile帮我们构建镜像。常见指令如下：</p><table><thead><tr><th>指令</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td>FROM</td><td>指定基础镜像</td><td>FROM centos:6</td></tr><tr><td>ENV</td><td>设置环境变量，可在后面指令使用</td><td>ENV key value</td></tr><tr><td>COPY</td><td>拷贝本地文件到镜像的指定目录</td><td>COPY ./jre11.tar.gz /tmp</td></tr><tr><td>RUN</td><td>执行Linux的shell命令，一般是安装过程的命令</td><td>RUN tar -zxvf /tmp/jrel1.tar.gz &amp;&amp; EXPORTS path=/tmp/jre11:$path</td></tr><tr><td>EXPOSE</td><td>指定容器运行时监听的端口，是给镜像使用者看的</td><td>EXP0SE 8080</td></tr><tr><td>ENTRYPOINT</td><td>镜像中应用的启动命令，容器运行时调用</td><td>ENTRYPOINT java -jar xx.jar</td></tr></tbody></table><p>我们可以基于Ubuntu基础镜像，利用Dockerfile描述镜像结构，+也可以直接基于JDK为基础镜像，省略前面的步骤：当编写好了Dockerfile，可以利用下面命令来构建镜像：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>docker build -t 镜像名:版本号 dockerfile所在目录</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-t：是给镜像起名，格式依然是repository:tag的格式，不指定tag时，默认为latest</p>',8)]))}const l=e(i,[["render",s]]),c=JSON.parse('{"path":"/tools/docker/3/","title":"3 自定义镜像","lang":"zh-CN","frontmatter":{"title":"3 自定义镜像","createTime":"2025/06/18 21:07:46","tags":["工具"],"permalink":"/tools/docker/3/"},"readingTime":{"minutes":1.34,"words":401},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/docker/3 自定义镜像.md","headers":[]}');export{l as comp,c as data};
